+        let burst = contributors
+            .iter()
+            .find(|c| c.code == "feature_burst_density_1s")
+            .expect("must have feature_burst_density_1s");
+        assert!(
+            (burst.signed_impact - 0.08 * 0.3).abs() < 1e-10,
